import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

/**
 * Tests for the format rerun functionality.
 * When format finds any lint violations in a file that can be autocorrected, it should automatically
 * rerun format on that file before returning the lint violations of the last format run.
 * To prevent infinite loops, no more than 3 reruns will be executed.
 */
class FormatRerunTest {

    @Test
    fun `Given a rule that requires multiple format runs to stabilize then format should rerun automatically`() {
        // This rule corrects "step1" to "step2" on first run, and "step2" to "final" on second run
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { MultiStepAutoCorrectRule() },
            ),
        )

        val code = "val x = step1"
        val expectedFinalCode = "val x = final"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        assertThat(actualFormattedCode).isEqualTo(expectedFinalCode)
    }

    @Test
    fun `Given a rule that requires 3 format runs to stabilize then format should rerun up to 3 times`() {
        // This rule requires 3 runs to fully stabilize
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { ThreeStepAutoCorrectRule() },
            ),
        )

        val code = "val x = step0"
        val expectedFinalCode = "val x = step3"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        assertThat(actualFormattedCode).isEqualTo(expectedFinalCode)
    }

    @Test
    fun `Given rules that would cause infinite loop then format should stop after max runs`() {
        // This rule always produces autocorrectable errors, which would cause infinite loop if not capped
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { InfiniteLoopRule() },
            ),
        )

        val code = "val x = test"

        // Should not hang or throw exception - should return after max runs
        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        // The code will be modified by the rule but should not cause infinite loop
        assertThat(actualFormattedCode).isNotNull()
    }

    @Test
    fun `Given no autocorrectable errors then format should not rerun`() {
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { NoAutoCorrectRule() },
            ),
        )

        val code = "val x = test"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        // Code should remain unchanged as there are no autocorrectable errors
        assertThat(actualFormattedCode).isEqualTo(code)
    }

    @Test
    fun `Given a rule that stabilizes after first run then format should not rerun`() {
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { SingleStepAutoCorrectRule() },
            ),
        )

        val code = "val x = old"
        val expectedFinalCode = "val x = new"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        assertThat(actualFormattedCode).isEqualTo(expectedFinalCode)
    }

    /**
     * A rule that requires multiple format runs to fully correct the code.
     * On first run: "step1" -> "step2"
     * On second run: "step2" -> "final"
     */
    private class MultiStepAutoCorrectRule : Rule(
        ruleId = RuleId("test:multi-step-autocorrect"),
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.IDENTIFIER && node.text == "step1") {
                emit(node.startOffset, "Should be step2", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("step2")
                }
            } else if (node.elementType == ElementType.IDENTIFIER && node.text == "step2") {
                emit(node.startOffset, "Should be final", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("final")
                }
            }
        }
    }

    /**
     * A rule that requires exactly 3 runs to fully correct the code.
     * step0 -> step1 -> step2 -> step3
     */
    private class ThreeStepAutoCorrectRule : Rule(
        ruleId = RuleId("test:three-step-autocorrect"),
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            when {
                node.elementType == ElementType.IDENTIFIER && node.text == "step0" -> {
                    emit(node.startOffset, "Should be step1", true)
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step1")
                    }
                }
                node.elementType == ElementType.IDENTIFIER && node.text == "step1" -> {
                    emit(node.startOffset, "Should be step2", true)
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step2")
                    }
                }
                node.elementType == ElementType.IDENTIFIER && node.text == "step2" -> {
                    emit(node.startOffset, "Should be step3", true)
                    if (autoCorrect) {
                        (node as LeafElement).rawReplaceWithText("step3")
                    }
                }
            }
        }
    }

    /**
     * A rule that always produces autocorrectable errors (simulating an infinite loop scenario).
     * This tests that the max runs limit prevents actual infinite loops.
     */
    private class InfiniteLoopRule : Rule(
        ruleId = RuleId("test:infinite-loop"),
        about = About(),
    ) {
        private var counter = 0

        override fun beforeFirstNode(editorConfig: com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig) {
            counter = 0
        }

        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.IDENTIFIER && node.text.startsWith("test")) {
                counter++
                emit(node.startOffset, "Error $counter", true)
                if (autoCorrect) {
                    // Always create a new autocorrectable error
                    (node as LeafElement).rawReplaceWithText("test$counter")
                }
            }
        }
    }

    /**
     * A rule that only reports non-autocorrectable errors.
     */
    private class NoAutoCorrectRule : Rule(
        ruleId = RuleId("test:no-autocorrect"),
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.IDENTIFIER && node.text == "test") {
                emit(node.startOffset, "Cannot be fixed", false)
            }
        }
    }

    /**
     * A rule that corrects everything in a single run.
     */
    private class SingleStepAutoCorrectRule : Rule(
        ruleId = RuleId("test:single-step-autocorrect"),
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.IDENTIFIER && node.text == "old") {
                emit(node.startOffset, "Should be new", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("new")
                }
            }
        }
    }
}
