import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

/**
 * Tests for the format rerun functionality.
 * When format finds any lint violations in a file that can be autocorrected, it should automatically
 * rerun format on that file before returning the lint violations of the last format run.
 * To prevent infinite loops, no more than 3 reruns will be executed.
 */
class FormatRerunTest {

    @Test
    fun `Given a rule that requires multiple format runs to stabilize then format should rerun automatically`() {
        // This rule corrects "step1" to "step2" on first run, and "step2" to "final" on second run
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { MultiStepAutoCorrectRule() },
            ),
        )

        val code = "val x = step1"
        val expectedFinalCode = "val x = final"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        assertThat(actualFormattedCode).isEqualTo(expectedFinalCode)
    }

    @Test
    fun `Given a rule that requires 3 format runs to stabilize then format should rerun up to 3 times`() {
        // This rule requires 3 runs to fully stabilize
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { ThreeStepAutoCorrectRule() },
            ),
        )

        val code = "val x = step0"
        val expectedFinalCode = "val x = step3"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        assertThat(actualFormattedCode).isEqualTo(expectedFinalCode)
    }

    @Test
    fun `Given rules that would cause infinite loop then format should stop after max runs`() {
        // This rule always produces autocorrectable errors, which would cause infinite loop if not capped
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { InfiniteLoopRule() },
            ),
        )

        val code = "val x = test"

        // Should not hang or throw exception - should return after max runs
        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        // The code will be modified by the rule but should not cause infinite loop
        assertThat(actualFormattedCode).isNotNull()
    }

    @Test
    fun `Given no autocorrectable errors then format should not rerun`() {
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { NoAutoCorrectRule() },
            ),
        )

        val code = "val x = test"

        val actualFormattedCode = ktLintRuleEngine.format(Code.fromSnippet(code))

        // Code should remain unchanged as there are no autocorrectable errors
        assertThat(actualFormattedCode).isEqualTo(code)
    }

    @Test
    fun `Given a rule that stabilizes after first run then format should not rerun`() {
        val ktLintRuleEngine = KtLintRuleEngine(
            ruleProviders = setOf(
                RuleProvider { SingleStepAutoCorrectRule() },
